/* eslint-env browser */
/**
 * Add-to-playlist: in-page selection + YouTube Data API insertion.
 *
 * Companion to the static daily-snippet reports generated by snippet_utils.py
 * and deployed to GitHub Pages. Expects window.CONFIG.CLIENT_ID and
 * window.CONFIG.PLAYLIST_ID to be defined (see config.example.js).
 *
 * No build step. Pure browser JS. Uses Google Identity Services for OAuth.
 */
(function () {
    'use strict';

    var YT_API = 'https://www.googleapis.com/youtube/v3/playlistItems?part=snippet';
    var YT_LIST_API = 'https://www.googleapis.com/youtube/v3/playlistItems';  // for fetching existing items
    var SCOPE = 'https://www.googleapis.com/auth/youtube';
    var DELAY_MS = 200;  // gap between sequential inserts to stay polite
    var TOKEN_KEY = 'yt_pl_token';      // localStorage key
    var TOKEN_SAFETY_MS = 60000;        // treat as expired 1 min before real expiry
    var DEDUP_KEY = 'yt_pl_existing';   // localStorage key for cached playlist IDs
    var DEDUP_TTL_MS = 10 * 60 * 1000;  // refresh playlist contents every 10 min

    var tokenClient = null;
    var accessToken = null;
    var tokenExpiresAt = 0;             // ms since epoch; 0 means unknown/expired
    var existingIds = null;             // Set of video IDs already in the target playlist

    // --- token cache (persists across page reloads) ---
    function loadStoredToken() {
        try {
            var raw = localStorage.getItem(TOKEN_KEY);
            if (!raw) return false;
            var obj = JSON.parse(raw);
            if (!obj || !obj.token || !obj.expiresAt) return false;
            if (Date.now() > obj.expiresAt - TOKEN_SAFETY_MS) return false;
            accessToken = obj.token;
            tokenExpiresAt = obj.expiresAt;
            return true;
        } catch (e) { return false; }
    }
    function storeToken(token, expiresInSec) {
        var expiresAt = Date.now() + (expiresInSec || 3600) * 1000;
        accessToken = token;
        tokenExpiresAt = expiresAt;
        try {
            localStorage.setItem(TOKEN_KEY, JSON.stringify({ token: token, expiresAt: expiresAt }));
        } catch (e) {}
    }
    function clearStoredToken() {
        accessToken = null;
        tokenExpiresAt = 0;
        try { localStorage.removeItem(TOKEN_KEY); } catch (e) {}
    }
    function tokenIsFresh() {
        return !!accessToken && Date.now() < tokenExpiresAt - TOKEN_SAFETY_MS;
    }

    // --- playlist-contents cache (persists across page reloads, 10-min TTL) ---
    // Lets us skip videos that are already in the target playlist before burning
    // a 50-quota-unit playlistItems.insert call on a duplicate. The list endpoint
    // costs 1 unit per 50-item page (negligible vs the inserts it avoids).
    function loadCachedExistingIds() {
        try {
            var raw = localStorage.getItem(DEDUP_KEY);
            if (!raw) return null;
            var obj = JSON.parse(raw);
            if (!obj || !obj.ids || !obj.cachedAt) return null;
            if (obj.playlistId !== window.CONFIG.PLAYLIST_ID) return null;
            if (Date.now() > obj.cachedAt + DEDUP_TTL_MS) return null;
            return new Set(obj.ids);
        } catch (e) { return null; }
    }
    function storeExistingIds(idSet) {
        try {
            localStorage.setItem(DEDUP_KEY, JSON.stringify({
                playlistId: window.CONFIG.PLAYLIST_ID,
                cachedAt: Date.now(),
                ids: Array.from(idSet)
            }));
        } catch (e) {}
    }
    /**
     * Paginate through playlistItems.list to collect every video ID already in
     * the target playlist. Returns a Promise resolving to a Set. On failure,
     * resolves to an empty Set so the batch can still proceed (without dedup).
     */
    function fetchExistingIds() {
        var ids = new Set();
        function fetchPage(pageToken) {
            var url = YT_LIST_API
                + '?part=contentDetails&maxResults=50'
                + '&playlistId=' + encodeURIComponent(window.CONFIG.PLAYLIST_ID)
                + (pageToken ? '&pageToken=' + encodeURIComponent(pageToken) : '');
            return fetch(url, {
                headers: { 'Authorization': 'Bearer ' + accessToken }
            }).then(function (r) {
                if (!r.ok) return null;
                return r.json();
            }).then(function (data) {
                if (!data) return null;
                (data.items || []).forEach(function (item) {
                    var v = item && item.contentDetails && item.contentDetails.videoId;
                    if (v) ids.add(v);
                });
                if (data.nextPageToken) return fetchPage(data.nextPageToken);
                return ids;
            }).catch(function () { return null; });
        }
        return fetchPage('').then(function (result) {
            return result || new Set();  // soft-fail = empty set = no dedup applied
        });
    }

    var bar = null;
    var btn = null;
    var countEl = null;
    var msgEl = null;

    // --- selection state ---
    function selectedCards() {
        return Array.prototype.slice.call(
            document.querySelectorAll('.snippet-card .vid-check:checked')
        ).map(function (cb) { return cb.closest('.snippet-card'); })
         .filter(function (card) { return card && card.dataset.videoId; });
    }

    function refreshCount() {
        var cards = selectedCards();
        countEl.textContent = String(cards.length);
        if (cards.length > 0) {
            bar.classList.add('visible');
            document.body.classList.add('has-bar');
        } else {
            bar.classList.remove('visible');
            document.body.classList.remove('has-bar');
        }
    }

    function setStatus(card, text, kind) {
        var el = card.querySelector('.snippet-status');
        if (!el) return;
        el.textContent = text;
        el.classList.remove('ok', 'err');
        if (kind) el.classList.add(kind);
    }

    function sleep(ms) {
        return new Promise(function (resolve) { setTimeout(resolve, ms); });
    }

    // --- OAuth ---
    function ensureTokenClient() {
        if (tokenClient) return;
        if (!window.google || !google.accounts || !google.accounts.oauth2) {
            throw new Error('Google Identity Services not loaded');
        }
        if (!window.CONFIG || !window.CONFIG.CLIENT_ID) {
            throw new Error('Missing CONFIG.CLIENT_ID — create assets/config.js');
        }
        tokenClient = google.accounts.oauth2.initTokenClient({
            client_id: window.CONFIG.CLIENT_ID,
            scope: SCOPE,
            callback: function () {}  // set per-request below
        });
    }

    function requestToken(forceConsent) {
        // Fast path: cached, still-fresh token — skip GIS entirely.
        if (!forceConsent && tokenIsFresh()) {
            return Promise.resolve(accessToken);
        }
        ensureTokenClient();
        return new Promise(function (resolve, reject) {
            var settled = false;
            var timer = setTimeout(function () {
                if (settled) return;
                settled = true;
                reject(new Error('Sign-in timed out'));
            }, 60000);
            tokenClient.callback = function (resp) {
                if (settled) return;
                settled = true;
                clearTimeout(timer);
                if (resp && resp.access_token) {
                    storeToken(resp.access_token, resp.expires_in);
                    resolve(resp.access_token);
                } else {
                    reject(new Error(resp && resp.error ? resp.error : 'Sign-in failed'));
                }
            };
            try {
                // Empty prompt lets GIS decide; only force consent on explicit retry.
                tokenClient.requestAccessToken({ prompt: forceConsent ? 'consent' : '' });
            } catch (e) {
                clearTimeout(timer);
                reject(e);
            }
        });
    }

    // --- YouTube API ---
    /**
     * @returns {Promise<{ok:boolean, reason?:string, fatal?:boolean}>}
     */
    function addOne(videoId) {
        var body = {
            snippet: {
                playlistId: window.CONFIG.PLAYLIST_ID,
                resourceId: { kind: 'youtube#video', videoId: videoId }
            }
        };
        return fetch(YT_API, {
            method: 'POST',
            headers: {
                'Authorization': 'Bearer ' + accessToken,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(body)
        }).then(function (r) {
            if (r.ok) return { ok: true };
            return r.json().then(function (data) {
                var err = (data && data.error) || {};
                var reason = (err.errors && err.errors[0] && err.errors[0].reason) || err.status || '';
                if (r.status === 401) return { ok: false, reason: 'auth', authExpired: true };
                if (r.status === 403 && /quota/i.test(reason)) return { ok: false, reason: 'quota', fatal: true };
                if (r.status === 404) return { ok: false, reason: 'unavailable' };
                if (reason === 'videoNotFound' || reason === 'forbidden') return { ok: false, reason: reason };
                return { ok: false, reason: reason || ('http ' + r.status) };
            }).catch(function () {
                return { ok: false, reason: 'http ' + r.status };
            });
        }).catch(function () {
            return { ok: false, reason: 'network' };
        });
    }

    // --- batch runner ---
    function setBarMsg(text) {
        msgEl.textContent = text;
    }

    /**
     * Returns a Promise<Set> of video IDs already in the playlist, using the
     * 10-min localStorage cache when possible. Falls back to an empty set
     * (no dedup) if the live fetch fails — never blocks the batch.
     */
    function ensureExistingIds() {
        if (existingIds) return Promise.resolve(existingIds);
        var cached = loadCachedExistingIds();
        if (cached) {
            existingIds = cached;
            return Promise.resolve(existingIds);
        }
        return fetchExistingIds().then(function (set) {
            existingIds = set;
            if (set.size > 0) storeExistingIds(set);
            return existingIds;
        });
    }

    function runBatch() {
        var cards = selectedCards();
        if (!cards.length) return;
        btn.disabled = true;
        setBarMsg('Authorising…');
        return requestToken().then(function () {
            setBarMsg('Checking playlist for duplicates…');
            return ensureExistingIds();
        }).then(function (existing) {
            setBarMsg('Adding ' + cards.length + ' (playlist has ' + existing.size + ')…');
            return cards.reduce(function (chain, card) {
                return chain.then(function (state) {
                    if (state.aborted) return state;
                    var vid = card.dataset.videoId;
                    // Short-circuit if the video is already in the playlist.
                    if (existing.has(vid)) {
                        setStatus(card, '↺ already in playlist', 'ok');
                        state.dupes += 1;
                        return state;  // no sleep — no API call was made
                    }
                    setStatus(card, '…');
                    return addOne(vid).then(function (r) {
                        if (!r.ok && r.authExpired && !state.retried) {
                            // Stored token rejected — wipe cache and request a new one.
                            state.retried = true;
                            clearStoredToken();
                            return requestToken(true).then(function () {
                                return addOne(vid);
                            }).then(function (r2) {
                                applyResult(card, r2, state, existing, vid);
                                return sleep(DELAY_MS).then(function () { return state; });
                            });
                        }
                        applyResult(card, r, state, existing, vid);
                        return sleep(DELAY_MS).then(function () { return state; });
                    });
                });
            }, Promise.resolve({ aborted: false, retried: false, done: 0, fail: 0, dupes: 0 })).then(function (state) {
                btn.disabled = false;
                if (existingIds && existingIds.size > 0) storeExistingIds(existingIds);
                if (state.aborted) {
                    setBarMsg('Quota exhausted — try again tomorrow');
                } else {
                    var c = selectedCards().length;
                    setBarMsg(c + ' selected · last batch: ' + state.done + ' added, '
                              + state.dupes + ' duplicate, ' + state.fail + ' failed');
                }
            });
        }).catch(function (e) {
            btn.disabled = false;
            setBarMsg('Sign-in cancelled or failed: ' + e.message);
        });
    }

    function applyResult(card, r, state, existing, vid) {
        if (r.ok) {
            setStatus(card, '✓ added', 'ok');
            state.done += 1;
            // Track this newly-added ID so a re-tick within the same batch
            // (or a re-click of the same card) is recognised as a duplicate.
            if (existing && vid) existing.add(vid);
        } else {
            setStatus(card, '✗ ' + r.reason, 'err');
            state.fail += 1;
            if (r.fatal) state.aborted = true;
        }
    }

    // --- init ---
    function init() {
        bar = document.getElementById('plBar');
        btn = document.getElementById('plBtn');
        countEl = document.getElementById('plCount');
        if (!bar || !btn || !countEl) return;  // page without the bar

        // Pre-load any cached token so the first click after page reload
        // can skip OAuth entirely (token is valid for ~1 hour).
        loadStoredToken();

        // Reserve a <span> for the live message; insert it in place of the count's parent contents
        msgEl = bar.querySelector('.playlist-bar-msg');
        var baseMsg = msgEl ? msgEl.innerHTML : '';

        // Selection wiring
        document.querySelectorAll('.snippet-card .vid-check').forEach(function (cb) {
            cb.addEventListener('change', function () {
                cb.closest('.snippet-card').classList.toggle('selected', cb.checked);
                // Restore base message format with current count
                if (msgEl) msgEl.innerHTML = baseMsg;
                refreshCount();
            });
        });
        refreshCount();

        btn.addEventListener('click', runBatch);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
